Here's how to handle each scenario with modern MSTest (3.9+):

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;

[TestClass]
public sealed class PlatformAndEnvironmentTests
{
    // 1. Windows-only: skip on Linux/macOS
    [TestMethod]
    [OSCondition(OperatingSystems.Windows)]
    public void Registry_ReadsExpectedValue()
    {
        var value = Registry.GetValue(@"HKEY_LOCAL_MACHINE\SOFTWARE\...", "Key", null);
        Assert.IsNotNull(value);
    }

    // 2. Skip in CI (requires local GPU)
    [TestMethod]
    [CICondition(ConditionMode.Exclude)]
    public void RenderFrame_ProducesValidOutput()
    {
        var frame = GpuRenderer.RenderFrame();
        Assert.IsNotNull(frame);
    }

    // 3. Flaky external API — retry up to 3 times
    [TestMethod]
    [Retry(3)]
    [Timeout(10000)]
    public async Task WeatherApi_ReturnsForecast(TestContext testContext)
    {
        var forecast = await WeatherClient.GetForecastAsync(testContext.CancellationToken);
        Assert.IsNotNull(forecast);
    }

    // 4. Cleanup temp files even on failure
    private string _tempFile = string.Empty;

    [TestInitialize]
    public void Setup()
    {
        _tempFile = Path.GetTempFileName();
    }

    [TestCleanup]
    public void Cleanup()
    {
        if (File.Exists(_tempFile))
            File.Delete(_tempFile);
    }

    [TestMethod]
    public void ProcessFile_WritesExpectedContent()
    {
        FileProcessor.Process(_tempFile);
        Assert.AreEqual("expected", File.ReadAllText(_tempFile));
    }
}
```

**Key points:**

| Scenario | Solution | Min Version |
|---|---|---|
| Windows-only | `[OSCondition(OperatingSystems.Windows)]` | 3.10+ |
| Skip in CI | `[CICondition(ConditionMode.Exclude)]` | 3.10+ |
| Flaky API | `[Retry(3)]` | 3.9+ |
| Cleanup on failure | `[TestCleanup]` method | Any |

- `[TestCleanup]` **always runs** after each test, even on failure — ideal for temp file deletion.
- `[Retry]` should only be used for genuinely flaky external dependencies, not to mask race conditions.
- Combine `[Retry]` with `[Timeout]` and `TestContext.CancellationToken` to bound retries.
